import re


HEADER_RE = re.compile(r'^(?P<name>[A-Za-z-]+):\s*(?P<val>.+)$')


class HeaderParser:
    def __init__(self, pattern=HEADER_RE):
        self.pattern = pattern

    def parse_header(self, line):
        m = self.pattern.match(line)
        if not m:
            return None
        name, val = m.group('name'), m.group('val')
        # BUG: returns dict, but caller tries to iterate as (k,v)
        return {'key': name, 'value': val}


def parse_header(line):
    return HeaderParser().parse_header(line)


def main():
    header = 'Content-Type: application/json'
    for k, v in parse_header(header):
        print(k, '=', v)


if __name__ == '__main__':
    main()
